class TOTPManager:
    """Manager class for handling multiple users' TOTP authentication"""
    
    def __init__(self, issuer: str = "MyApp"):
        self.authenticator = TOTPAuthenticator(issuer=issuer)
        self.user_secrets = {}
        self.failed_attempts = {}
        self.max_failed_attempts = 5
        self.lockout_duration = 300
    
    def register_user(self, user_id: str, account_name: str) -> Tuple[str, str, BytesIO]:
        """Register a new user and generate their TOTP secret"""
        secret, uri, qr_code = self.authenticator.get_provisioning_data(account_name)
        
        self.user_secrets[user_id] = {
            'secret': secret,
            'account_name': account_name,
            'created_at': int(time.time())
        }
        
        return secret, uri, qr_code
    
    def verify_user_token(self, user_id: str, token: str) -> bool:
        """Verify a user's TOTP token with rate limiting"""
        if user_id not in self.user_secrets:
            return False
        
        if self._is_locked_out(user_id):
            return False
        
        secret = self.user_secrets[user_id]['secret']
        
        is_valid = self.authenticator.verify_totp(secret, token, window=1)
        
        if not is_valid:
            self._record_failed_attempt(user_id)
        else:
            self._clear_failed_attempts(user_id)
        
        return is_valid
    
    def _is_locked_out(self, user_id: str) -> bool:
        """Check if user is locked out due to too many failed attempts"""
        if user_id not in self.failed_attempts:
            return False
        
        attempts_data = self.failed_attempts[user_id]
        
        if attempts_data['count'] >= self.max_failed_attempts:
            time_since_lockout = int(time.time()) - attempts_data['last_attempt']
            
            if time_since_lockout < self.lockout_duration:
                return True
            else:
                self._clear_failed_attempts(user_id)
                return False
        
        return False
    
    def _record_failed_attempt(self, user_id: str):
        """Record a failed authentication attempt"""
        current_time = int(time.time())
        
        if user_id not in self.failed_attempts:
            self.failed_attempts[user_id] = {
                'count': 0,
                'last_attempt': current_time
            }
        
        self.failed_attempts[user_id]['count'] += 1
        self.failed_attempts[user_id]['last_attempt'] = current_time
    
    def _clear_failed_attempts(self, user_id: str):
        """Clear failed attempts for a user"""
        if user_id in self.failed_attempts:
            del self.failed_attempts[user_id]
    
    def get_user_secret(self, user_id: str) -> Optional[str]:
        """Get a user's TOTP secret (use with caution)"""
        if user_id in self.user_secrets:
            return self.user_secrets[user_id]['secret']
        return None
    
    def remove_user(self, user_id: str) -> bool:
        """Remove a user's TOTP configuration"""
        if user_id in self.user_secrets:
            del self.user_secrets[user_id]
            self._clear_failed_attempts(user_id)
            return True
        return False


